/* global Accelerometer, GravitySensor, Gyroscope, AbsoluteOrientationSensor */
import React, { useEffect, useState } from "react";
import { Card, Typography, Grid, Box, useTheme } from "@mui/material";
import {
  ResponsiveContainer,
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
} from "recharts";

const getColors = (mode) => ({
  x: mode === "dark" ? "#8884d8" : "#0000ff",
  y: mode === "dark" ? "#82ca9d" : "#008000",
  z: mode === "dark" ? "#ffc658" : "#ffcc00",
  w: mode === "dark" ? "#f54242" : "#ff0000",
  pitch: mode === "dark" ? "#8884d8" : "#0000ff",
  roll: mode === "dark" ? "#82ca9d" : "#008000",
  yaw: mode === "dark" ? "#ffc658" : "#ffcc00",
  compass: mode === "dark" ? "#8884d8" : "#0000ff",
});

const useSensor = (sensorName, createSensor, processReading) => {
  const [data, setData] = useState({});
  const [max, setMax] = useState({});
  const [min, setMin] = useState({});
  const [chartData, setChartData] = useState([]);

  useEffect(() => {
    if (!createSensor) return;

    let sensor;
    try {
      sensor = createSensor();
      sensor.addEventListener("reading", () => {
        const newData = processReading(sensor);

        // Update max and min
        setMax((prevMax) => ({
          ...prevMax,
          ...Object.keys(newData).reduce((acc, key) => {
            acc[key] = Math.max(prevMax[key] || -Infinity, newData[key]);
            return acc;
          }, {}),
        }));

        setMin((prevMin) => ({
          ...prevMin,
          ...Object.keys(newData).reduce((acc, key) => {
            acc[key] = Math.min(prevMin[key] || Infinity, newData[key]);
            return acc;
          }, {}),
        }));

        setData(newData);

        // Update chart data
        setChartData((current) => {
          const newPoint = { ...newData, timestamp: Date.now() };
          const maxLength = 100;
          return current.length >= maxLength
            ? [...current.slice(1), newPoint]
            : [...current, newPoint];
        });
      });
      sensor.start();
    } catch (err) {
      console.error(`${sensorName} not supported or permission denied:`, err);
    }

    return () => {
      if (sensor) sensor.stop();
    };
  }, [createSensor, processReading, sensorName]);

  return { data, max, min, chartData };
};

const useSensors = () => {
  const accelerometer = useSensor(
    "Accelerometer",
    () => new Accelerometer({ frequency: 60 }),
    (sensor) => ({
      x: sensor.x / 9.8,
      y: sensor.y / 9.8,
      z: sensor.z / 9.8,
    })
  );

  const gravity = useSensor(
    "GravitySensor",
    () => new GravitySensor({ frequency: 60 }),
    (sensor) => ({
      x: sensor.x / 9.8,
      y: sensor.y / 9.8,
      z: sensor.z / 9.8,
    })
  );

  const gyroscope = useSensor(
    "Gyroscope",
    () => new Gyroscope({ frequency: 60 }),
    (sensor) => ({
      x: sensor.x,
      y: sensor.y,
      z: sensor.z,
    })
  );

  const orientation = useSensor(
    "AbsoluteOrientationSensor",
    () => new AbsoluteOrientationSensor({ frequency: 60 }),
    (sensor) => {
      const [x, y, z, w] = sensor.quaternion;
      return { x, y, z, w };
    }
  );

  const inclinometer = useSensor("Inclinometer", null, (sensor) => {
    const { alpha, beta, gamma } = sensor;
    if (
      typeof alpha === "number" &&
      typeof beta === "number" &&
      typeof gamma === "number"
    ) {
      return {
        pitch: beta,
        roll: gamma,
        yaw: alpha,
        compass: 360 - alpha,
      };
    }
    return {};
  });

  const compass = useSensor("Compass", null, null);

  return {
    accelerometer,
    gravity,
    gyroscope,
    orientation,
    inclinometer,
    compass,
  };
};

const SensorChart = ({ data, colors }) => (
  <Box sx={{ height: 250 }}>
    <ResponsiveContainer width="100%" height="100%">
      <LineChart data={data}>
        <CartesianGrid strokeDasharray="3 3" />
        <XAxis dataKey="timestamp" hide={true} />
        <YAxis />
        <Tooltip transitionDuration={0} />
        {Object.keys(data[0] || {})
          .filter((key) => key !== "timestamp")
          .map((axis) => (
            <Line
              key={axis}
              type="monotone"
              dataKey={axis}
              stroke={colors[axis]}
              isAnimationActive={false}
              dot={false}
              strokeWidth={3}
            />
          ))}
      </LineChart>
    </ResponsiveContainer>
  </Box>
);

const SensorSection = ({ sensors }) => {
  const theme = useTheme();
  const colors = getColors(theme.palette.mode);

  return (
    <>
      {Object.entries(sensors).map(([sensorType, sensor]) => (
        <Grid item xs={12} md={6} lg={4} key={sensorType}>
          <Card sx={{ height: 500, mb: 4 }}>
            <Box sx={{ height: 200, overflow: "auto", p: 2 }}>
              <Typography variant="h5" component="h2">
                {sensorType.charAt(0).toUpperCase() + sensorType.slice(1)}
              </Typography>
              {Object.entries(sensor.data || {})
                .filter(([_, value]) => value !== null && value !== undefined)
                .map(([key, value]) => (
                  <Typography key={key} style={{ color: colors[key] }}>
                    {`${key.toUpperCase()}: ${value.toFixed(
                      4
                    )} (Max: ${sensor.max[key]?.toFixed(4)}, Min: ${sensor.min[
                      key
                    ]?.toFixed(4)})`}
                  </Typography>
                ))}
            </Box>
            <SensorChart data={sensor.chartData} colors={colors} />
          </Card>
        </Grid>
      ))}
    </>
  );
};

const SensorPage = () => {
  const sensors = useSensors();

  return (
    <Grid container spacing={4} sx={{ py: 4, px: 2 }}>
      <SensorSection sensors={sensors} />
    </Grid>
  );
};

export default SensorPage;
